// HealthComponent.h — reusable on any Actor
UCLASS(ClassGroup=(Custom), meta=(BlueprintSpawnableComponent))
class UHealthComponent : public UActorComponent
{
    GENERATED_BODY()
public:
    UHealthComponent();

    UPROPERTY(EditAnywhere, BlueprintReadWrite, Category = "Health")
    float MaxHealth = 100.f;

    UPROPERTY(ReplicatedUsing=OnRep_CurrentHealth, BlueprintReadOnly, Category = "Health")
    float CurrentHealth;

    UPROPERTY(EditAnywhere, BlueprintReadWrite, Category = "Health")
    bool bInvincible = false;

    DECLARE_DYNAMIC_MULTICAST_DELEGATE_TwoParams(FOnHealthChanged, float, NewHealth, float, Delta);
    DECLARE_DYNAMIC_MULTICAST_DELEGATE(FOnDeath);

    UPROPERTY(BlueprintAssignable)
    FOnHealthChanged OnHealthChanged;

    UPROPERTY(BlueprintAssignable)
    FOnDeath OnDeath;

protected:
    virtual void BeginPlay() override;

    UFUNCTION()
    void HandleTakeAnyDamage(AActor* DamagedActor, float Damage,
        const UDamageType* DamageType, AController* Instigator, AActor* DamageCauser);

    UFUNCTION()
    void OnRep_CurrentHealth();
};

// HealthComponent.cpp
void UHealthComponent::BeginPlay()
{
    Super::BeginPlay();
    CurrentHealth = MaxHealth;
    GetOwner()->OnTakeAnyDamage.AddDynamic(this, &UHealthComponent::HandleTakeAnyDamage);
}

void UHealthComponent::HandleTakeAnyDamage(AActor* DamagedActor, float Damage,
    const UDamageType* DamageType, AController* Instigator, AActor* DamageCauser)
{
    if (bInvincible || CurrentHealth <= 0.f) return;

    CurrentHealth = FMath::Clamp(CurrentHealth - Damage, 0.f, MaxHealth);
    OnHealthChanged.Broadcast(CurrentHealth, -Damage);

    if (CurrentHealth <= 0.f)
    {
        OnDeath.Broadcast();
    }
}

// Any Actor using it — the Actor decides what death means
AMyEnemy::AMyEnemy()
{
    HealthComp = CreateDefaultSubobject<UHealthComponent>(TEXT("HealthComp"));
}

void AMyEnemy::BeginPlay()
{
    Super::BeginPlay();
    HealthComp->OnDeath.AddDynamic(this, &AMyEnemy::HandleDeath);
}

void AMyEnemy::HandleDeath()
{
    // Enemy decides its own death: ragdoll, drop loot, etc.
}
